local G = DYCInfoPanel local require = G.DYCModRequire local odwutil = require( "dyc_odwutil" ) local ShowObjectDetail = odwutil.ShowObjectDetail local ClearUpdateOdwTask = odwutil.ClearUpdateOdwTask local CreateUpdateOdwTask = odwutil.CreateUpdateOdwTask local function OnGainFocus(self, ...) local owner = self.owner ShowObjectDetail(owner, self) ClearUpdateOdwTask(self) CreateUpdateOdwTask(self, owner) return self.dycOldOnGainFocus(self, ...) end local function OnLoseFocus(self, ...) ShowObjectDetail(nil, self) ClearUpdateOdwTask(self) return self.dycOldOnLoseFocus(self, ...) end local function DYCBadge(self) self.dycOldOnGainFocus = self.OnGainFocus self.OnGainFocus = OnGainFocus self.dycOldOnLoseFocus = self.OnLoseFocus self.OnLoseFocus = OnLoseFocus end return DYCBadge 